class Solution:
    def transformArray(self, nums):
        evens = sum(1 for x in nums if x % 2 == 0)
        odds = len(nums) - evens
        return [0] * evens + [1] * odds

solutions.python:
class Solution:
    def transformArray(self, nums):
        return sorted(0 if x % 2 == 0 else 1 for x in nums)

